Date: {{signature_date}}',
  '[{"id":"party_a_email","token":"{{party_a_email}}","label":"Your Email","description":"Client email","category":"party_a","type":"email","required":true,"autofillKey":"email"},{"id":"party_a_name","token":"{{party_a_name}}","label":"Your Name","description":"Client name","category":"party_a","type":"text","required":true,"autofillKey":"name"},{"id":"party_a_address","token":"{{party_a_address}}","label":"Your Address","description":"Client address","category":"party_a","type":"textarea","required":false,"autofillKey":"address"},{"id":"party_a_company","token":"{{party_a_company}}","label":"Your Company","description":"Client company","category":"party_a","type":"text","required":false,"autofillKey":"company_name"},{"id":"party_a_title","token":"{{party_a_title}}","label":"Your Title","description":"Job title","category":"party_a","type":"text","required":false,"autofillKey":"job_title"},{"id":"party_b_email","token":"{{party_b_email}}","label":"Freelancer Email","description":"Freelancer email","category":"party_b","type":"email","required":true},{"id":"party_b_name","token":"{{party_b_name}}","label":"Freelancer Name","description":"Freelancer name","category":"party_b","type":"text","required":true},{"id":"party_b_address","token":"{{party_b_address}}","label":"Freelancer Address","description":"Freelancer address","category":"party_b","type":"textarea","required":false},{"id":"party_b_company","token":"{{party_b_company}}","label":"Trading Name","description":"Freelancer trading name","category":"party_b","type":"text","required":false},{"id":"effective_date","token":"{{effective_date}}","label":"Start Date","description":"Agreement start date","category":"dates","type":"date","required":true},{"id":"expiration_date","token":"{{expiration_date}}","label":"End Date","description":"Agreement end date","category":"dates","type":"date","required":false},{"id":"signature_date","token":"{{signature_date}}","label":"Signature Date","description":"Date of signing","category":"dates","type":"date","required":false},{"id":"notice_period","token":"{{notice_period}}","label":"Notice Period","description":"Days notice for termination","category":"terms","type":"number","required":false},{"id":"confidentiality_period","token":"{{confidentiality_period}}","label":"Confidentiality Period","description":"Years of confidentiality obligation","category":"terms","type":"number","required":false},{"id":"hourly_rate","token":"{{hourly_rate}}","label":"Rate","description":"Hourly or daily rate","category":"financial","type":"currency","required":false},{"id":"payment_amount","token":"{{payment_amount}}","label":"Project Fee","description":"Total project fee","category":"financial","type":"currency","required":false},{"id":"services_description","token":"{{services_description}}","label":"Services","description":"Description of services","category":"project","type":"textarea","required":false}]'::jsonb,
  true,
